command:
// =========================
// LANDMARK GENERATOR
// Sandbox Generator
// Shows all rolls + descriptions
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

// -------------------------
// BIOME SELECTION
// -------------------------

let biome;

if (globalThis.currentHexBiome) {

    biome = globalThis.currentHexBiome;

    ui.notifications.info(
        `Using biome from Master Hex Generator: ${biome}`
    );

} else {

    biome = await Dialog.prompt({
        title: "Select Biome",
        content: `
        <p>Select the biome for the lair:</p>
        <select id="biome">
        <option>Grassland</option>
        <option>Forest</option>
        <option>Hills</option>
        <option>Marsh</option>
        <option>Mountains</option>
        </select>
        `,
        callback: html => html.find("#biome").val()
    });

}

// -------------------------
// DESCRIPTIONS
// -------------------------

const landmarkTypeDescriptions = {
    Natural: "A natural feature of the land, such as animals, plants, stone formations, caves, rivers, or other terrain features.",
    Artificial: "A constructed or altered feature, such as ruins, roads, shrines, signs, camps, bridges, or old structures.",
    Magic: "A supernatural or enchanted feature caused by magic, old rituals, strange phenomena, or places of power."
};

const categoryDescriptions = {
    "Fauna": "Animal-related signs, remains, nests, hunting grounds, or evidence of creatures living here.",
    "Flora (A)": "Plant-related landmarks such as trees, flowers, thickets, bushes, or strange growth.",
    "Flora (B)": "More unusual plant or fungal features, such as mushrooms, roots, thickets, or mycelial growth.",
    "Geology (A)": "Stone, earth, caves, pits, crystals, craters, and other major land formations.",
    "Geology (B)": "Rock formations, ravines, sinkholes, stone bridges, stairs, and unusual terrain shapes.",
    "Hydrology": "Water features such as rivers, springs, lakes, ponds, waterfalls, caves, or streams.",

    "Labor": "Signs of work, farming, production, storage, camps, fields, or harvested land.",
    "Mystery": "Strange signs, bones, standing stones, totems, masks, or unsettling markers.",
    "Ruin": "Destroyed, abandoned, collapsed, or overgrown remains of past habitation.",
    "Small Structure": "Minor built features like cabins, wells, fences, hunting towers, or bivouacs.",
    "Travel": "Travel-related features such as roads, bridges, signs, ledges, stairs, or crossings.",
    "Worship": "Religious or burial features such as shrines, tombs, holy places, idols, or cemeteries.",

    "Area Under a Spell": "A whole area affected by ongoing magic, curse, protection, weather, or strange supernatural law.",
    "Enchanted Item": "A magical object or feature that may grant knowledge, healing, mutation, visions, or other effects.",
    "Magic Path": "A magical route or crossing that exists because of supernatural forces.",
    "Magic Remains": "Visible traces left behind by magic, rituals, battles, corruption, or magical destruction.",
    "Place of Power": "A sacred, ancient, or magically important place where rituals, power, or visions may occur.",
    "Strange Phenomenon": "A weird magical effect that defies normal explanation."
};

const contentDescriptions = {
    Hazard: "The place is dangerous by itself. It could collapse, be trapped, cursed, unstable, poisonous, or otherwise harmful.",
    Empty: "The place is not dangerous or occupied by monsters. Instead, characters may learn information about the world, nearby threats, secrets, or lore.",
    Special: "There is a mystery to solve, a problem happening, a dispute, a puzzle, a threat, or someone in need. The reward is usually case-by-case.",
    Monsters: "Creatures are present around the landmark. They may live here, guard it, hunt nearby, investigate it, or simply be traveling through."
};

// -------------------------
// LANDMARK TABLES
// -------------------------

const natural = {
    "Fauna": [
        "Animal boneyard", "Anthill", "Beaver dam", "Giant animal skeleton",
        "Giant bird nest", "Giant snail shell", "Huge galleries",
        "Location covered with crows", "Predator's hunting ground", "Ransacked area"
    ],
    "Flora (A)": [
        "Berry bush", "Bramble overgrown area", "Burnt area", "Centennial tree",
        "Dead tree", "Exotic tree", "Fallen tree", "Flower circle",
        "Fruit tree", "Giant flower"
    ],
    "Flora (B)": [
        "Giant mushroom", "Hollow tree", "Impenetrable thicket", "Mushroom circle",
        "Mushroom spot", "Mycelial proliferation", "Rare plant spot",
        "Root arch", "Tree alignment", "Water-filled plant"
    ],
    "Geology (A)": [
        "Animal shaped rock", "Cave", "Chasm", "Crater",
        "Crystalline proliferation", "Giant crystal", "Lava pool",
        "Mudpit", "Pit", "Precious metal vein"
    ],
    "Geology (B)": [
        "Ravine", "Rift", "Rock hole", "Rock needle", "Scree",
        "Sinkhole", "Stone arch", "Stone bridge", "Stone stairs", "Very big rock"
    ],
    "Hydrology": [
        "Ford", "Hotspring", "Lake", "Pond", "Rapids",
        "River", "Spring", "Stream", "Water-filled cave", "Waterfall"
    ]
};

const artificial = {
    "Labor": [
        "Barn", "Felled trees", "Field", "Granary", "Labor camp",
        "Meadow", "Quarry", "Straw man", "Swidden field", "Water tower"
    ],
    "Mystery": [
        "Carved rock", "Dolmen", "Hanging bones", "Heads on spikes",
        "Masks", "Pile of bones", "Rock stack", "Standing stones",
        "Straw dolls", "Totem"
    ],
    "Ruin": [
        "Abandoned tavern", "Burnt barn", "Collapsed mine entrance",
        "Decrepit mansion", "Desecrated church", "Destroyed house",
        "Overgrown tower", "Pile of rubble", "Razed village", "Ruined castle"
    ],
    "Small Structure": [
        "Bench", "Bivouac area", "Gazebo", "Hunter's cabin", "Hunting tower",
        "Kennel", "Outhouse", "Palisade", "Well", "Wooden fence"
    ],
    "Travel": [
        "Boardwalks", "Boundary stone", "Bridge", "Broken bridge",
        "Danger sign", "Ledge", "Signboard", "Stairs",
        "Suspension bridge", "Zipline"
    ],
    "Worship": [
        "Bell/Gong", "Calvary", "Cemetery", "Cross", "Holy place",
        "Idol", "Shrine", "Tomb", "Tumulus", "Vault"
    ]
};

const magic = {
    "Area Under a Spell": [
        "Always snowy area", "Anti-magic zone", "Area bringing back the dead",
        "Area where nothing grows", "Bad luck area", "Dome of darkness",
        "Force field", "Incessant cyclone", "Protection from Evil", "Time is frozen"
    ],
    "Enchanted Item": [
        "Curative basin", "Enchanted bell", "Fertility stone",
        "Magic fountain/spring", "Magic fruits tree", "Mutation pit",
        "Stone of knowledge", "Sword stuck in a rock", "Visions pool", "Witch cauldron"
    ],
    "Magic Path": [
        "Breathable water", "Glowing mushroom trail", "Illusory path",
        "Invisible bridge", "Levitating staircase", "Magic mirror",
        "Rainbow bridge", "Riddle bridge", "Walkable water", "Wormhole"
    ],
    "Magic Remains": [
        "Area covered with fairy dust", "Bloody altar", "Corpse covered in crystals",
        "Corrupt area", "Destroyed golem", "Magic battlefield",
        "Old shrine", "Petrified travelers", "Remnants of ceremony", "Signs of explosion"
    ],
    "Place of Power": [
        "Ancient burial grounds", "Birthplace/Tomb of a saint", "Magic beacon",
        "Mana well", "Neolithic rock monument", "Preserved natural place",
        "Root of the World Tree", "Sacred waters", "Sun focal point", "Ziggurat of old"
    ],
    "Strange Phenomenon": [
        "Everburning tree", "Evermelting ice", "Floating crystal",
        "Ghost building", "Luminous engravings", "Reverse waterfall",
        "Singing crystal", "Strong magnetism", "Talking rock", "Whispers in the wind"
    ]
};

// -------------------------
// CONTENT TABLES
// -------------------------

const hazards = [
    "Acid pits", "Allergenic plants", "Ancient dormant illness", "Curse",
"Dangerous footing", "Easy to get lost", "Fog", "Fumes",
"Ghosts", "Hallucinogenic spores", "Hidden pits", "Hunting traps",
"Magic corruption", "Plague", "Quicksands", "Radiations",
"Sabotage/Trap", "Unstable/Likely to break", "Venomous animals", "Volcanic area"
];

const emptyInfo = [
    "Info about nearby monsters", "Alchemy recipe", "Curative effects",
"Directions to a settlement", "Dungeon location", "Future event",
"Important past event", "Legend/Myth", "Local custom", "Password",
"Secret passage location", "Spell/Ritual", "Tale about a magic weapon",
"Toxicity of something", "Upcoming weather", "Words from a random monster language"
];

const specials = [
    "Arbitrate a dispute",
"Prevent a threat",
"Solve a puzzle/riddle",
"Uncover a mystery",
"NPC(s)/Monster(s) in need",
"Related to landmark"
];

const monsters = {
    Grassland: ["Dinosaurs", "Ogres", "Gnolls", "Orcs", "Goblins", "Giant rats", "Wolves", "Bandits", "Berserkers", "Worgs", "Werewolves"],
    Forest: ["Ents", "Giant spiders", "Ogres", "Bears", "Goblins", "Boars", "Wolves", "Bandits", "Elves", "Dryads", "Werewolves"],
    Hills: ["Manticores", "Basilisks", "Ogres", "Orcs", "Goblins", "Giant rats", "Wolves", "Bandits", "Beastmen", "Giants", "Wyverns"],
    Marsh: ["Moth-men", "Mushroom-men", "Frog-men", "Trolls", "Skeletons", "Crocodiles", "Zombies", "Orcs", "Lizard-men", "Snake-men", "Hydras"],
    Mountains: ["Giants", "Griffins", "Dwarves", "Kobolds", "Orcs", "Bears", "Wolves", "Bandits", "Berserkers", "Smilodons", "Vampires"]
};

// -------------------------
// LANDMARK TYPE
// -------------------------

let typeRoll = roll(6);
let landmarkSet;
let landmarkType;

if (typeRoll <= 3) {
    landmarkType = "Natural";
    landmarkSet = natural;
} else if (typeRoll <= 5) {
    landmarkType = "Artificial";
    landmarkSet = artificial;
} else {
    landmarkType = "Magic";
    landmarkSet = magic;
}

const categories = Object.keys(landmarkSet);

let categoryRoll = roll(6);
let category = categories[categoryRoll - 1];

let landmarkRoll = roll(10);
let landmark = landmarkSet[category][landmarkRoll - 1];

// -------------------------
// CONTENT
// -------------------------

let contentRoll = roll(6);
let content;
let detailRoll;
let detail;
let detailDie;
let treasureChance;

if (contentRoll === 1) {
    content = "Hazard";
    treasureChance = 25;
    detailDie = 20;
    detailRoll = roll(detailDie);
    detail = hazards[detailRoll - 1];
} else if (contentRoll <= 3) {
    content = "Empty";
    treasureChance = 15;
    detailDie = 20;
    detailRoll = roll(detailDie);
    detail = emptyInfo[detailRoll - 1];
} else if (contentRoll === 4) {
    content = "Special";
    treasureChance = "Variable";
    detailDie = 6;
    detailRoll = roll(detailDie);
    detail = specials[detailRoll - 1];
} else {
    content = "Monsters";
    treasureChance = 50;
    detailDie = 12;
    detailRoll = roll(detailDie);
    detail = monsters[biome][detailRoll - 2]; // biome encounter table runs 2-12
}

// -------------------------
// TREASURE
// -------------------------

let treasureRoll = roll(100);
let treasureResult;

if (treasureChance === "Variable") {
    treasureResult = "Variable / decide based on the situation";
} else {
    treasureResult =
    treasureRoll <= treasureChance
    ? `Yes (${treasureRoll} ≤ ${treasureChance}%)`
    : `No (${treasureRoll} > ${treasureChance}%)`;
}

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>Landmark Generator</h2>

<p><b>Biome:</b> ${biome}</p>

<hr>

<h3>Landmark</h3>

<p><b>Landmark Type Roll:</b> d6 = ${typeRoll}</p>
<p><b>Landmark Type:</b> ${landmarkType}</p>
<p><i>${landmarkTypeDescriptions[landmarkType]}</i></p>

<p><b>Category Roll:</b> d6 = ${categoryRoll}</p>
<p><b>Category:</b> ${category}</p>
<p><i>${categoryDescriptions[category]}</i></p>

<p><b>${category} Roll:</b> d10 = ${landmarkRoll}</p>
<p><b>Landmark:</b> ${landmark}</p>

<hr>

<h3>Content</h3>

<p><b>Content Roll:</b> d6 = ${contentRoll}</p>
<p><b>Content:</b> ${content}</p>
<p><i>${contentDescriptions[content]}</i></p>

<p><b>${content} Roll:</b> d${detailDie} = ${detailRoll}</p>
<p><b>Detail:</b> ${detail}</p>

<hr>

<h3>Treasure</h3>

<p><b>Treasure Chance:</b> ${treasureChance}${treasureChance !== "Variable" ? "%" : ""}</p>
<p><b>Treasure Roll:</b> d100 = ${treasureRoll}</p>
<p><b>Treasure:</b> ${treasureResult}</p>

<p><i>Use treasure as anything worth discovering: coins, supplies, clues, maps, trade goods, useful gear, secrets, reputation, an ally, or a magic item.</i></p>
`;

ChatMessage.create({
    speaker: ChatMessage.getSpeaker(),
                   content: output
});
